import { Component, OnInit, ViewChild, ElementRef, AfterViewInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';

interface AnnotationObject {
  id: string;
  type: 'rect' | 'polygon' | 'point' | 'polyline' | 'mask';
  label: string;
  points: Array<{x: number, y: number}>;
  color: string;
  confidence?: number;
  attributes?: {[key: string]: string | number | boolean};
  occluded?: boolean;
  rotation?: number;
}

interface DrawingState {
  isDrawing: boolean;
  startX: number;
  startY: number;
  currentPoints: Array<{x: number, y: number}>;
}

@Component({
  selector: 'app-annotation',
  templateUrl: './annotation.component.html',
  styleUrls: ['./annotation.component.css']
})
export class AnnotationComponent implements OnInit, AfterViewInit {
  @ViewChild('canvas', { static: false }) canvasRef!: ElementRef<HTMLCanvasElement>;
  @ViewChild('fileInput', { static: false }) fileInput!: ElementRef<HTMLInputElement>;

  project: any = { name: 'My Project', labelSet: ['person', 'car', 'dog', 'cat'] };
  currentFileIndex = 0;
  files: File[] = [];
  currentImage: HTMLImageElement | null = null;

  annotations: AnnotationObject[] = [];
  selectedAnnotationId: string | null = null;
  selectedTool: 'select' | 'rect' | 'polygon' | 'point' | 'brush' | 'eraser' | 'polyline' = 'rect';
  selectedLabel: string | null = null;
  drawingState: DrawingState = {
    isDrawing: false,
    startX: 0,
    startY: 0,
    currentPoints: []
  };

  canvas!: HTMLCanvasElement;
  ctx!: CanvasRenderingContext2D;
  zoomLevel = 1;
  panX = 0;
  panY = 0;

  showAttributesPanel = false;
  showExportPanel = false;
  brushSize = 5;
  brushOpacity = 1;
  gridEnabled = false;
  snapToGrid = false;

  history: AnnotationObject[][] = [];
  historyIndex = -1;

  labels: {name: string, color: string, attributes?: string[]}[] = [];
  labelColors = [
    '#FF6B6B', '#4ECDC4', '#45B7D1', '#FFA07A', '#98D8C8',
    '#F7DC6F', '#BB8FCE', '#85C1E2', '#F8B88B', '#A3E4D7'
  ];

  constructor(private route: ActivatedRoute, private router: Router) {
    this.initializeLabels(this.project.labelSet);
  }

  ngOnInit(): void {}

  ngAfterViewInit(): void {
    this.canvas = this.canvasRef.nativeElement;
    this.ctx = this.canvas.getContext('2d')!;
    this.setupCanvasEventListeners();
    this.setupKeyboardShortcuts();
  }

  initializeLabels(labelSet: string[]): void {
    this.labels = labelSet.map((label, idx) => ({
      name: label,
      color: this.labelColors[idx % this.labelColors.length],
      attributes: []
    }));
    if (this.labels.length > 0) {
      this.selectedLabel = this.labels[0].name;
    }
  }

  setupCanvasEventListeners(): void {
    this.canvas.addEventListener('mousedown', (e) => this.onCanvasMouseDown(e));
    this.canvas.addEventListener('mousemove', (e) => this.onCanvasMouseMove(e));
    this.canvas.addEventListener('mouseup', (e) => this.onCanvasMouseUp(e));
    this.canvas.addEventListener('wheel', (e) => this.onCanvasWheel(e), false);
    this.canvas.addEventListener('contextmenu', (e) => e.preventDefault());
    this.canvas.addEventListener('dblclick', (e) => this.onCanvasDoubleClick(e));
  }

  setupKeyboardShortcuts(): void {
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape') this.cancelDrawing();
      if (e.key === 'r' || e.key === 'R') this.setTool('rect');
      if (e.key === 'p' || e.key === 'P') this.setTool('polygon');
      if (e.key === 'd' || e.key === 'D') this.setTool('point');
      if (e.key === 'b' || e.key === 'B') this.setTool('brush');
      if (e.key === 'e' || e.key === 'E') this.setTool('eraser');
      if (e.key === 'l' || e.key === 'L') this.setTool('polyline');
      if (e.key === 's' || e.key === 'S') this.setTool('select');
      if (e.key === 'Delete' && this.selectedAnnotationId) this.deleteAnnotation(this.selectedAnnotationId);
      if ((e.ctrlKey || e.metaKey) && e.key === 'z') this.undo();
      if ((e.ctrlKey || e.metaKey) && e.key === 'y') this.redo();
      if (e.key === 'g' || e.key === 'G') this.gridEnabled = !this.gridEnabled;
      if (e.key === 't' || e.key === 'T') this.snapToGrid = !this.snapToGrid;
    });
  }

  private getCanvasCoords(event: MouseEvent): {x: number, y: number} {
    const rect = this.canvas.getBoundingClientRect();
    return {
      x: (event.clientX - rect.left - this.panX) / this.zoomLevel,
      y: (event.clientY - rect.top - this.panY) / this.zoomLevel
    };
  }

  onCanvasMouseDown(event: MouseEvent): void {
    if (!this.currentImage) return;
    const {x, y} = this.getCanvasCoords(event);

    if (this.selectedTool === 'select') {
      this.selectAnnotationAtPoint(x, y);
      return;
    }

    this.drawingState.isDrawing = true;
    this.drawingState.startX = x;
    this.drawingState.startY = y;
    this.drawingState.currentPoints = [{x, y}];
  }

  onCanvasMouseMove(event: MouseEvent): void {
    if (!this.currentImage) return;
    const {x, y} = this.getCanvasCoords(event);

    if (!this.drawingState.isDrawing) {
      this.render();
      return;
    }

    if (this.selectedTool === 'rect') {
      this.render();
      this.drawRectPreview(this.drawingState.startX, this.drawingState.startY, x, y);
    } else if (this.selectedTool === 'polygon' || this.selectedTool === 'polyline') {
      this.render();
      this.drawPolygonPreview(this.drawingState.currentPoints, x, y);
    } else if (this.selectedTool === 'brush') {
      this.drawBrush(x, y);
    } else if (this.selectedTool === 'eraser') {
      this.drawEraser(x, y);
    }
  }

  onCanvasMouseUp(event: MouseEvent): void {
    if (!this.drawingState.isDrawing) return;
    const {x, y} = this.getCanvasCoords(event);

    if (this.selectedTool === 'rect') {
      this.finalizeRect(this.drawingState.startX, this.drawingState.startY, x, y);
      this.drawingState.isDrawing = false;
    } else if (this.selectedTool === 'point') {
      this.addPoint(x, y);
      this.drawingState.isDrawing = false;
    }

    this.render();
  }

  onCanvasWheel(event: WheelEvent): void {
    event.preventDefault();
    const delta = event.deltaY > 0 ? 0.9 : 1.1;
    this.zoomLevel = Math.max(0.1, Math.min(5, this.zoomLevel * delta));
    this.render();
  }

  onCanvasDoubleClick(event: MouseEvent): void {
    if (this.selectedTool === 'polygon' || this.selectedTool === 'polyline') {
      this.finalizePolygon(this.drawingState.currentPoints);
      this.drawingState.isDrawing = false;
      this.render();
    }
  }

  drawRectPreview(x1: number, y1: number, x2: number, y2: number): void {
    const color = this.getSelectedLabelColor();
    this.ctx.strokeStyle = color;
    this.ctx.lineWidth = 2 / this.zoomLevel;
    this.ctx.strokeRect(x1 * this.zoomLevel + this.panX, y1 * this.zoomLevel + this.panY, (x2 - x1) * this.zoomLevel, (y2 - y1) * this.zoomLevel);
  }

  drawPolygonPreview(points: Array<{x: number, y: number}>, currentX: number, currentY: number): void {
    if (points.length === 0) return;
    const color = this.getSelectedLabelColor();
    this.ctx.strokeStyle = color;
    this.ctx.lineWidth = 2 / this.zoomLevel;
    this.ctx.fillStyle = color + '33';

    const allPoints = [...points, {x: currentX, y: currentY}];
    this.ctx.beginPath();
    this.ctx.moveTo(allPoints[0].x * this.zoomLevel + this.panX, allPoints[0].y * this.zoomLevel + this.panY);
    for (let i = 1; i < allPoints.length; i++) {
      this.ctx.lineTo(allPoints[i].x * this.zoomLevel + this.panX, allPoints[i].y * this.zoomLevel + this.panY);
    }
    if (points.length > 2) {
      this.ctx.lineTo(points[0].x * this.zoomLevel + this.panX, points[0].y * this.zoomLevel + this.panY);
    }
    this.ctx.stroke();
  }

  drawBrush(x: number, y: number): void {
    const color = this.getSelectedLabelColor();
    this.ctx.globalAlpha = this.brushOpacity;
    this.ctx.fillStyle = color;
    this.ctx.beginPath();
    this.ctx.arc(x * this.zoomLevel + this.panX, y * this.zoomLevel + this.panY, (this.brushSize / 2) * this.zoomLevel, 0, Math.PI * 2);
    this.ctx.fill();
    this.ctx.globalAlpha = 1;
  }

  drawEraser(x: number, y: number): void {
    this.ctx.clearRect((x - this.brushSize / 2) * this.zoomLevel + this.panX, (y - this.brushSize / 2) * this.zoomLevel + this.panY, this.brushSize * this.zoomLevel, this.brushSize * this.zoomLevel);
  }

  finalizeRect(x1: number, y1: number, x2: number, y2: number): void {
    if (Math.abs(x2 - x1) < 2 || Math.abs(y2 - y1) < 2) return;
    const annotation: AnnotationObject = {
      id: this.generateId(),
      type: 'rect',
      label: this.selectedLabel || 'unknown',
      points: [{x: Math.min(x1, x2), y: Math.min(y1, y2)}, {x: Math.max(x1, x2), y: Math.max(y1, y2)}],
      color: this.getSelectedLabelColor()
    };
    this.addAnnotationToHistory();
    this.annotations.push(annotation);
  }

  finalizePolygon(points: Array<{x: number, y: number}>): void {
    if (points.length < 3) return;
    const annotation: AnnotationObject = {
      id: this.generateId(),
      type: this.selectedTool as 'polygon' | 'polyline',
      label: this.selectedLabel || 'unknown',
      points: points,
      color: this.getSelectedLabelColor()
    };
    this.addAnnotationToHistory();
    this.annotations.push(annotation);
    this.drawingState.currentPoints = [];
  }

  addPoint(x: number, y: number): void {
    const annotation: AnnotationObject = {
      id: this.generateId(),
      type: 'point',
      label: this.selectedLabel || 'unknown',
      points: [{x, y}],
      color: this.getSelectedLabelColor()
    };
    this.addAnnotationToHistory();
    this.annotations.push(annotation);
  }

  selectAnnotationAtPoint(x: number, y: number): void {
    for (let i = this.annotations.length - 1; i >= 0; i--) {
      const ann = this.annotations[i];
      if (this.pointInAnnotation(x, y, ann)) {
        this.selectedAnnotationId = ann.id;
        return;
      }
    }
    this.selectedAnnotationId = null;
  }

  pointInAnnotation(x: number, y: number, ann: AnnotationObject): boolean {
    if (ann.type === 'rect' && ann.points.length === 2) {
      const [p1, p2] = ann.points;
      return x >= p1.x && x <= p2.x && y >= p1.y && y <= p2.y;
    } else if (ann.type === 'point') {
      return Math.hypot(x - ann.points[0].x, y - ann.points[0].y) < 10;
    } else if (ann.type === 'polygon') {
      return this.pointInPolygon(x, y, ann.points);
    }
    return false;
  }

  pointInPolygon(x: number, y: number, polygon: Array<{x: number, y: number}>): boolean {
    let inside = false;
    for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
      const xi = polygon[i].x, yi = polygon[i].y;
      const xj = polygon[j].x, yj = polygon[j].y;
      const intersect = ((yi > y) !== (yj > y)) && (x < ((xj - xi) * (y - yi)) / (yj - yi) + xi);
      if (intersect) inside = !inside;
    }
    return inside;
  }

  deleteAnnotation(id: string): void {
    this.addAnnotationToHistory();
    this.annotations = this.annotations.filter(a => a.id !== id);
    this.selectedAnnotationId = null;
  }

  updateAnnotationLabel(id: string, label: string): void {
    const ann = this.annotations.find(a => a.id === id);
    if (ann) {
      this.addAnnotationToHistory();
      ann.label = label;
      ann.color = this.getColorForLabel(label);
    }
  }

  render = (): void => {
    if (!this.currentImage) return;
    this.ctx.fillStyle = '#f5f5f5';
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    this.ctx.save();
    this.ctx.translate(this.panX, this.panY);
    this.ctx.scale(this.zoomLevel, this.zoomLevel);
    this.ctx.drawImage(this.currentImage, 0, 0);

    if (this.gridEnabled) {
      this.drawGrid();
    }

    this.annotations.forEach((ann) => {
      const isSelected = ann.id === this.selectedAnnotationId;
      this.drawAnnotation(ann, isSelected);
    });

    this.ctx.restore();
  }

  drawGrid(spacing: number = 50): void {
    this.ctx.strokeStyle = '#ddd';
    this.ctx.lineWidth = 0.5;
    for (let x = 0; x < this.currentImage!.width; x += spacing) {
      this.ctx.beginPath();
      this.ctx.moveTo(x, 0);
      this.ctx.lineTo(x, this.currentImage!.height);
      this.ctx.stroke();
    }
    for (let y = 0; y < this.currentImage!.height; y += spacing) {
      this.ctx.beginPath();
      this.ctx.moveTo(0, y);
      this.ctx.lineTo(this.currentImage!.width, y);
      this.ctx.stroke();
    }
  }

  drawAnnotation(ann: AnnotationObject, isSelected: boolean): void {
    const color = ann.color;
    const strokeWidth = isSelected ? 3 : 2;

    this.ctx.strokeStyle = color;
    this.ctx.lineWidth = strokeWidth;
    this.ctx.fillStyle = color + '33';

    if (ann.type === 'rect') {
      const [p1, p2] = ann.points;
      this.ctx.fillRect(p1.x, p1.y, p2.x - p1.x, p2.y - p1.y);
      this.ctx.strokeRect(p1.x, p1.y, p2.x - p1.x, p2.y - p1.y);
      this.drawLabel(ann.label, p1.x, p1.y - 5, color);
      if (isSelected) {
        this.drawSelectionHandles([p1, p2]);
      }
    } else if (ann.type === 'polygon') {
      this.ctx.beginPath();
      this.ctx.moveTo(ann.points[0].x, ann.points[0].y);
      for (let i = 1; i < ann.points.length; i++) {
        this.ctx.lineTo(ann.points[i].x, ann.points[i].y);
      }
      this.ctx.lineTo(ann.points[0].x, ann.points[0].y);
      this.ctx.fill();
      this.ctx.stroke();
      if (isSelected) {
        this.drawSelectionHandles(ann.points);
      }
      this.drawLabel(ann.label, ann.points[0].x, ann.points[0].y - 5, color);
    } else if (ann.type === 'point') {
      const [p] = ann.points;
      this.ctx.fillStyle = color;
      this.ctx.beginPath();
      this.ctx.arc(p.x, p.y, 5, 0, Math.PI * 2);
      this.ctx.fill();
      this.ctx.stroke();
      this.drawLabel(ann.label, p.x + 10, p.y, color);
    }
  }

  drawLabel(text: string, x: number, y: number, color: string): void {
    this.ctx.font = 'bold 12px Arial';
    const metrics = this.ctx.measureText(text);
    const textWidth = metrics.width;
    this.ctx.fillStyle = color;
    this.ctx.fillRect(x, y - 14, textWidth + 6, 14);
    this.ctx.fillStyle = 'white';
    this.ctx.fillText(text, x + 3, y - 2);
  }

  drawSelectionHandles(points: Array<{x: number, y: number}>): void {
    this.ctx.fillStyle = '#667eea';
    points.forEach(p => {
      this.ctx.fillRect(p.x - 4, p.y - 4, 8, 8);
    });
  }

  addAnnotationToHistory(): void {
    this.history = this.history.slice(0, this.historyIndex + 1);
    this.history.push(JSON.parse(JSON.stringify(this.annotations)));
    this.historyIndex++;
  }

  undo(): void {
    if (this.historyIndex > 0) {
      this.historyIndex--;
      this.annotations = JSON.parse(JSON.stringify(this.history[this.historyIndex]));
      this.render();
    }
  }

  redo(): void {
    if (this.historyIndex < this.history.length - 1) {
      this.historyIndex++;
      this.annotations = JSON.parse(JSON.stringify(this.history[this.historyIndex]));
      this.render();
    }
  }

  cancelDrawing(): void {
    this.drawingState.isDrawing = false;
    this.drawingState.currentPoints = [];
    this.render();
  }

  uploadImage(): void {
    this.fileInput.nativeElement.click();
  }

  onFileSelected(event: Event): void {
    const input = event.target as HTMLInputElement;
    if (input.files) {
      this.files = Array.from(input.files);
      this.currentFileIndex = 0;
      this.loadFile(0);
    }
  }

  loadFile(index: number): void {
    if (index < 0 || index >= this.files.length) return;
    const file = this.files[index];
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        this.currentImage = img;
        this.canvas.width = img.width;
        this.canvas.height = img.height;
        this.annotations = [];
        this.selectedAnnotationId = null;
        this.render();
      };
      img.src = e.target?.result as string;
    };
    reader.readAsDataURL(file);
  }

  nextFile(): void {
    if (this.currentFileIndex < this.files.length - 1) {
      this.currentFileIndex++;
      this.loadFile(this.currentFileIndex);
    }
  }

  previousFile(): void {
    if (this.currentFileIndex > 0) {
      this.currentFileIndex--;
      this.loadFile(this.currentFileIndex);
    }
  }

  exportAnnotations(format: string): void {
    const data = {format, image: this.files[this.currentFileIndex]?.name, annotations: this.annotations};
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `annotations.${format}.json`;
    a.click();
  }

  saveAnnotations(): void {
    alert(`Saved ${this.annotations.length} annotations`);
  }

  setTool(tool: any): void {
    this.selectedTool = tool;
    this.cancelDrawing();
  }

  generateId(): string {
    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }

  getSelectedLabelColor(): string {
    const label = this.labels.find(l => l.name === this.selectedLabel);
    return label?.color || '#667eea';
  }

  getColorForLabel(name: string): string {
    const label = this.labels.find(l => l.name === name);
    return label?.color || '#667eea';
  }

  toggleExportPanel(): void {
    this.showExportPanel = !this.showExportPanel;
  }

  getSelectedAnnotation(): AnnotationObject | null {
    return this.annotations.find(a => a.id === this.selectedAnnotationId) || null;
  }

  Math = Math;
}
<div class="annotation-workspace">
  <!-- Left Toolbar -->
  <div class="toolbar-left">
    <div class="toolbar-section">
      <div class="toolbar-title">Tools</div>

      <button 
        class="tool-button" 
        [class.active]="selectedTool === 'select'"
        (click)="setTool('select')"
        title="Select (S)">
        <svg width="20" height="20" viewBox="0 0 20 20" fill="none" stroke="currentColor">
          <path d="M3 3l8 8m0 0l-8 8m8-8l8-8m-8 8l8 8"/>
        </svg>
      </button>

      <button 
        class="tool-button"
        [class.active]="selectedTool === 'rect'"
        (click)="setTool('rect')"
        title="Rectangle (R)">
        <svg width="20" height="20" viewBox="0 0 20 20" fill="none" stroke="currentColor">
          <rect x="3" y="4" width="14" height="12" rx="1"/>
        </svg>
      </button>

      <button 
        class="tool-button"
        [class.active]="selectedTool === 'polygon'"
        (click)="setTool('polygon')"
        title="Polygon (P)">
        <svg width="20" height="20" viewBox="0 0 20 20" fill="none" stroke="currentColor">
          <path d="M10 2L18 8L15 17H5L2 8Z"/>
        </svg>
      </button>

      <button 
        class="tool-button"
        [class.active]="selectedTool === 'polyline'"
        (click)="setTool('polyline')"
        title="Polyline">
        <svg width="20" height="20" viewBox="0 0 20 20" fill="none" stroke="currentColor">
          <polyline points="2,18 8,8 14,14 18,4"/>
        </svg>
      </button>

      <button 
        class="tool-button"
        [class.active]="selectedTool === 'point'"
        (click)="setTool('point')"
        title="Point (D)">
        <svg width="20" height="20" viewBox="0 0 20 20" fill="currentColor">
          <circle cx="10" cy="10" r="3"/>
        </svg>
      </button>

      <hr class="toolbar-divider">

      <button 
        class="tool-button"
        [class.active]="selectedTool === 'brush'"
        (click)="setTool('brush')"
        title="Brush (B)">
        <svg width="20" height="20" viewBox="0 0 20 20" fill="none" stroke="currentColor">
          <path d="M3 17C5 14 8 12 12 12C14 12 16 13 17 15M3 17L4 13M3 17L7 16"/>
        </svg>
      </button>

      <button 
        class="tool-button"
        [class.active]="selectedTool === 'eraser'"
        (click)="setTool('eraser')"
        title="Eraser (E)">
        <svg width="20" height="20" viewBox="0 0 20 20" fill="none" stroke="currentColor">
          <path d="M2 18L8 12L16 4L18 6L10 14L4 20H2V18Z"/>
        </svg>
      </button>

      <hr class="toolbar-divider">

      <button class="tool-button" (click)="uploadImage()" title="Upload Image">
        <svg width="20" height="20" viewBox="0 0 20 20" fill="none" stroke="currentColor">
          <path d="M3 7V16C3 17.1 3.9 18 5 18H15C16.1 18 17 17.1 17 16V7M7 9L10 6L13 9M10 6V15"/>
        </svg>
      </button>

      <input 
        #fileInput
        type="file" 
        multiple 
        accept="image/*,video/*" 
        (change)="onFileSelected($event)"
        style="display:none">
    </div>

    <div class="toolbar-section">
      <div class="toolbar-title">Brush Settings</div>
      <div class="brush-control">
        <label>Size: {{ brushSize }}px</label>
        <input type="range" [(ngModel)]="brushSize" min="1" max="50" class="slider">
      </div>
      <div class="brush-control">
        <label>Opacity: {{ (brushOpacity * 100).toFixed(0) }}%</label>
        <input type="range" [(ngModel)]="brushOpacity" min="0.1" max="1" step="0.1" class="slider">
      </div>
    </div>

    <div class="toolbar-section">
      <div class="toolbar-title">View</div>
      <button 
        class="tool-button" 
        [class.active]="gridEnabled"
        (click)="gridEnabled = !gridEnabled">
        <span style="font-size: 12px;">Grid (G)</span>
      </button>
      <button 
        class="tool-button"
        [class.active]="snapToGrid"
        (click)="snapToGrid = !snapToGrid">
        <span style="font-size: 12px;">Snap (T)</span>
      </button>
    </div>

    <div class="toolbar-section">
      <div class="toolbar-title">Zoom: {{ (zoomLevel * 100).toFixed(0) }}%</div>
      <button class="tool-button" (click)="zoomLevel = Math.max(0.1, zoomLevel - 0.2)">−</button>
      <button class="tool-button" (click)="zoomLevel = 1">Fit</button>
      <button class="tool-button" (click)="zoomLevel = Math.min(5, zoomLevel + 0.2)">+</button>
    </div>

    <div class="toolbar-section">
      <div class="toolbar-title">Shortcuts</div>
      <div class="shortcuts-list">
        <div><strong>R</strong> Rectangle</div>
        <div><strong>P</strong> Polygon</div>
        <div><strong>D</strong> Point</div>
        <div><strong>B</strong> Brush</div>
        <div><strong>E</strong> Eraser</div>
        <div><strong>S</strong> Select</div>
        <div><strong>Del</strong> Delete</div>
        <div><strong>Ctrl+Z</strong> Undo</div>
        <div><strong>Ctrl+Y</strong> Redo</div>
        <div><strong>G</strong> Grid</div>
      </div>
    </div>
  </div>

  <!-- Canvas Area -->
  <div class="canvas-area">
    <div class="canvas-wrapper">
      <canvas 
        #canvas
        class="annotation-canvas"
        [style.cursor]="selectedTool === 'select' ? 'pointer' : 'crosshair'">
      </canvas>
    </div>

    <!-- Bottom Navigation -->
    <div class="bottom-navigation">
      <div class="nav-left">
        <button (click)="previousFile()" [disabled]="currentFileIndex === 0">
          ← Previous
        </button>
        <span class="frame-info">
          {{ currentFileIndex + 1 }} / {{ files.length }}
        </span>
        <button (click)="nextFile()" [disabled]="currentFileIndex === files.length - 1">
          Next →
        </button>
      </div>
      <div class="nav-center">
        <input 
          type="range" 
          [min]="0" 
          [max]="files.length - 1"
          [(ngModel)]="currentFileIndex"
          (change)="loadFile(currentFileIndex)"
          class="frame-slider">
      </div>
      <div class="nav-right">
        <button (click)="saveAnnotations()" class="btn-save">
          💾 Save
        </button>
        <button (click)="toggleExportPanel()" class="btn-export">
          📥 Export
        </button>
      </div>
    </div>
  </div>

  <!-- Right Panel -->
  <div class="panel-right">
    <div class="panel-section">
      <div class="panel-title">Labels</div>
      <div class="labels-container">
        <button 
          *ngFor="let label of labels"
          class="label-button"
          [class.selected]="selectedLabel === label.name"
          (click)="selectedLabel = label.name"
          [style.border-left-color]="label.color">
          <span class="label-color" [style.background-color]="label.color"></span>
          <span class="label-name">{{ label.name }}</span>
        </button>
      </div>
    </div>

    <div class="panel-section">
      <div class="panel-title">Objects ({{ annotations.length }})</div>
      <div class="objects-container">
        <div 
          *ngFor="let ann of annotations"
          class="object-item"
          [class.selected]="selectedAnnotationId === ann.id"
          (click)="selectedAnnotationId = ann.id; render()">
          <div class="object-header">
            <span class="object-color" [style.background-color]="ann.color"></span>
            <span class="object-label">{{ ann.label }}</span>
            <span class="object-type">({{ ann.type }})</span>
            <button 
              class="object-delete"
              (click)="deleteAnnotation(ann.id); $event.stopPropagation()">
              ×
            </button>
          </div>
          <div *ngIf="selectedAnnotationId === ann.id" class="object-details">
            <select (change)="updateAnnotationLabel(ann.id, $event.target.value)" class="object-select">
              <option>Change label...</option>
              <option *ngFor="let label of labels" [value]="label.name">{{ label.name }}</option>
            </select>
            <label *ngIf="ann.type !== 'point'" class="checkbox">
              <input type="checkbox" [(ngModel)]="ann.occluded">
              Occluded
            </label>
            <label class="checkbox">
              <input type="number" [(ngModel)]="ann.confidence" min="0" max="1" step="0.1" placeholder="Confidence">
            </label>
          </div>
        </div>
        <div *ngIf="annotations.length === 0" class="empty-state">
          No objects annotated
        </div>
      </div>
    </div>

    <div class="panel-section" *ngIf="showAttributesPanel">
      <div class="panel-title" (click)="toggleAttributesPanel()">
        ⚙ Attributes
      </div>
      <div class="attributes-container" *ngIf="getSelectedAnnotation()">
        <!-- Attributes form would go here -->
      </div>
    </div>

    <div class="panel-section" *ngIf="showExportPanel">
      <div class="panel-title" (click)="toggleExportPanel()">
        📤 Export Options
      </div>
      <div class="export-container">
        <button (click)="exportAnnotations('coco')" class="export-btn">COCO Format</button>
        <button (click)="exportAnnotations('voc')" class="export-btn">Pascal VOC</button>
        <button (click)="exportAnnotations('yolo')" class="export-btn">YOLO Format</button>
        <button (click)="exportAnnotations('json')" class="export-btn">JSON</button>
      </div>
    </div>

    <div class="panel-section">
      <div class="panel-title">History</div>
      <div class="history-controls">
        <button (click)="undo()" [disabled]="historyIndex <= 0">↶ Undo</button>
        <button (click)="redo()" [disabled]="historyIndex >= history.length - 1">↷ Redo</button>
      </div>
    </div>
  </div>
</div>
